@org.springframework.boot.test.context.SpringBootTest
class AccountLockingIT {
    @org.springframework.beans.factory.annotation.Autowired
    private AccountRepository accountRepository;

    @org.springframework.beans.factory.annotation.Autowired
    private org.springframework.transaction.support.TransactionTemplate txTemplate;

    @org.junit.jupiter.api.Test
    void optimisticLockingShouldFailSecondWriter() {
        Long id = txTemplate.execute(status -> accountRepository.save(new Account(java.math.BigDecimal.valueOf(100))).getId());

        Account snapshot1 = txTemplate.execute(status -> accountRepository.findById(id).orElseThrow());
        Account snapshot2 = txTemplate.execute(status -> accountRepository.findById(id).orElseThrow());

        txTemplate.executeWithoutResult(status -> {
            Account a1 = accountRepository.findById(snapshot1.getId()).orElseThrow();
            a1.setBalance(java.math.BigDecimal.valueOf(90));
        });

        org.junit.jupiter.api.Assertions.assertThrows(
            org.springframework.orm.ObjectOptimisticLockingFailureException.class,
            () -> txTemplate.executeWithoutResult(status -> {
                Account a2 = accountRepository.findById(snapshot2.getId()).orElseThrow();
                a2.setBalance(java.math.BigDecimal.valueOf(80));
                accountRepository.flush();
            })
        );
    }
}

